using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- Set up options with a default resolver so metadata is auto-generated ---
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver(),
    WriteIndented    = true
};

// ========================================================================
// 1. GetTypeInfo<T>()  –  returns JsonTypeInfo<T> directly (no cast needed)
// ========================================================================
JsonTypeInfo<WeatherForecast> typedInfo = options.GetTypeInfo<WeatherForecast>();
Console.WriteLine($"Typed metadata for: {typedInfo.Type.Name}");
Console.WriteLine($"  Kind          : {typedInfo.Kind}");
Console.WriteLine($"  Properties    : {string.Join(", ", typedInfo.Properties.Select(p => p.Name))}");

// Quick round-trip using the typed metadata
var forecast = new WeatherForecast("Seattle", 62);
string json = JsonSerializer.Serialize(forecast, typedInfo);
Console.WriteLine($"  Serialized    : {json}");

WeatherForecast? rt = JsonSerializer.Deserialize(json, typedInfo);
Console.WriteLine($"  Deserialized  : {rt}");

Console.WriteLine();

// ========================================================================
// 2. TryGetTypeInfo  –  probe without throwing
// ========================================================================

// 2a. A type the resolver CAN handle (WeatherForecast)
if (options.TryGetTypeInfo(typeof(WeatherForecast), out JsonTypeInfo? info))
{
    Console.WriteLine($"✔ Metadata available for {info.Type.Name}");
}
else
{
    Console.WriteLine("✘ No metadata for WeatherForecast");
}

// 2b. Use a resolver that only knows about ONE type, then ask for another.
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new LimitedResolver() // only knows WeatherForecast
};

if (limited.TryGetTypeInfo(typeof(string), out _))
{
    Console.WriteLine("✔ Metadata available for String (unexpected)");
}
else
{
    Console.WriteLine("✘ No metadata for String — resolver doesn't support it (no exception thrown)");
}

// === Types ===============================================================
public record WeatherForecast(string City, int TempF);

// A custom resolver that deliberately supports only WeatherForecast.
file class LimitedResolver : IJsonTypeInfoResolver
{
    private readonly DefaultJsonTypeInfoResolver _inner = new();

    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options)
    {
        if (type == typeof(WeatherForecast))
            return _inner.GetTypeInfo(type, options);

        return null; // "I don't know this type"
    }
}

